on_write:
let res = #{ action: "Allow" };
if !payload.contains("shape") || !payload.contains("dimensions") {
    res.action = "Reject";
    res.reason = "Array/Tensor payloads must define shape and dimension metrics";
}
res

on_read:
let res = #{ payload: payload };
if payload.dimensions == query_key {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
